mapper.select:
SELECT h.EMP_CODE AS empCode, h.EMP_NAME AS empName, h.DEPT_CODE AS deptCode, d.DEPT_NAME AS deptName, ISNULL(s.SHIFT_CODE, '') AS workPlanCode, ISNULL(s.SHIFT_NAME, '미설정') AS workPlanName, ISNULL(s.WORK_DAY_TYPE, 'WORK') AS workDayType, LEFT(CONVERT(VARCHAR(8), s.WORK_ON_HHMM, 108), 5) AS shiftOnTime, LEFT(CONVERT(VARCHAR(8), s.WORK_OFF_HHMM, 108), 5) AS shiftOffTime, weekly.weekWorkMin AS shiftWorkMin, r.REQ_ID AS requestId, r.REQ_GROUP AS existingRequestGroup, CASE WHEN r.REQ_GROUP = 'OTHER' THEN o.CHANGE_SHIFT_CODE ELSE r.REQ_TYPE END AS requestWorkCode, r.REASON AS reason, r.REASON_DETAIL AS reasonDetail, LEFT(CONVERT(VARCHAR(8), g.START_TIME, 108), 5) AS startTime, ISNULL(g.START_TIME_TYPE, 'N0') AS startTimeType, LEFT(CONVERT(VARCHAR(8), g.END_TIME, 108), 5) AS endTime, ISNULL(g.END_TIME_TYPE, 'N0') AS endTimeType, g.WORK_MIN AS requestWorkMin, r.STATUS AS status, r.REQUESTER_EMP_CODE AS requesterCode, re.EMP_NAME AS requesterName FROM HRIMASTER01 h LEFT JOIN ORGDEPTMASTER01 d ON h.COMPANY = d.COMPANY AND h.DEPT_CODE = d.DEPT_CODE LEFT JOIN HRTWORKPATTERNMASTER01 pm ON d.COMPANY = pm.COMPANY AND d.WORK_PATTERN_CODE = pm.WORK_PATTERN_CODE LEFT JOIN ( SELECT COMPANY, WORK_PATTERN_CODE, COUNT(*) AS CYCLE_LEN FROM HRTWORKPATTERNDETAIL01 GROUP BY COMPANY, WORK_PATTERN_CODE ) pdcount ON pm.COMPANY = pdcount.COMPANY AND pm.WORK_PATTERN_CODE = pdcount.WORK_PATTERN_CODE LEFT JOIN HRTWORKPATTERNDETAIL01 pd ON pm.COMPANY = pd.COMPANY AND pm.WORK_PATTERN_CODE = pd.WORK_PATTERN_CODE AND pd.SEQ = ( (DATEDIFF(DAY, pm.START_DATE, CAST(#{workDate} AS DATE)) % pdcount.CYCLE_LEN + pdcount.CYCLE_LEN) % pdcount.CYCLE_LEN + 1 ) LEFT JOIN HRTSHIFTMASTER01 s ON pd.COMPANY = s.COMPANY AND pd.SHIFT_CODE = s.SHIFT_CODE OUTER APPLY ( SELECT ISNULL(SUM( CASE WHEN ws.WORK_ON_HHMM IS NOT NULL AND ws.WORK_OFF_HHMM IS NOT NULL THEN (CASE WHEN ws.WORK_OFF_HHMM >= ws.WORK_ON_HHMM THEN DATEDIFF(MINUTE, ws.WORK_ON_HHMM, ws.WORK_OFF_HHMM) ELSE 1440 + DATEDIFF(MINUTE, ws.WORK_ON_HHMM, ws.WORK_OFF_HHMM) END - ISNULL(DATEDIFF(MINUTE, ws.BREAK1_START_HHMM, ws.BREAK1_END_HHMM), 0) - ISNULL(DATEDIFF(MINUTE, ws.BREAK2_START_HHMM, ws.BREAK2_END_HHMM), 0)) ELSE 0 END ), NULL) AS weekWorkMin FROM (VALUES(0),(1),(2),(3),(4),(5),(6)) AS days(n) INNER JOIN HRTWORKPATTERNDETAIL01 wpd ON pm.COMPANY IS NOT NULL AND pdcount.CYCLE_LEN IS NOT NULL AND wpd.COMPANY = pm.COMPANY AND wpd.WORK_PATTERN_CODE = pm.WORK_PATTERN_CODE AND wpd.SEQ = ( (DATEDIFF(DAY, pm.START_DATE, DATEADD(DAY, days.n, DATEADD(DAY, 1 - DATEPART(WEEKDAY, CAST(#{workDate} AS DATE)), CAST(#{workDate} AS DATE)))) % pdcount.CYCLE_LEN + pdcount.CYCLE_LEN) % pdcount.CYCLE_LEN + 1 ) INNER JOIN HRTSHIFTMASTER01 ws ON wpd.COMPANY = ws.COMPANY AND wpd.SHIFT_CODE = ws.SHIFT_CODE ) weekly LEFT JOIN HRTATTENDANCEREQUEST01 r ON h.COMPANY = r.COMPANY AND h.EMP_CODE = r.TARGET_EMP_CODE AND r.TARGET_DATE = CAST(#{workDate} AS DATE) AND r.STATUS <> 'CANCELED' LEFT JOIN HRTATTENDANCE_GENERAL01 g ON r.COMPANY = g.COMPANY AND r.REQ_ID = g.REQ_ID LEFT JOIN HRTATTENDANCE_OTHER01 o ON r.COMPANY = o.COMPANY AND r.REQ_ID = o.REQ_ID LEFT JOIN HRIMASTER01 re ON r.COMPANY = re.COMPANY AND r.REQUESTER_EMP_CODE = re.EMP_CODE WHERE h.COMPANY = #{company} AND h.DEPT_CODE = #{deptCode} AND h.RETIRE_DATE IS NULL
AND h.EMP_CODE = #{loginEmpCode}
AND s.WORK_DAY_TYPE IN ('OFF', 'HOLIDAY')
AND (s.WORK_DAY_TYPE IS NULL OR s.WORK_DAY_TYPE NOT IN ('OFF', 'HOLIDAY'))
AND h.EMP_CODE = #{empCode}
AND s.SHIFT_CODE = #{workPlanFilter}
ORDER BY h.EMP_CODE

SELECT COUNT(*)
FROM HRTATTENDANCEREQUEST01 r
LEFT JOIN HRTATTENDANCE_OTHER01 o
       ON r.COMPANY = o.COMPANY AND r.REQ_ID = o.REQ_ID
WHERE r.COMPANY = #{company}
  AND r.TARGET_EMP_CODE = #{empCode}
  AND r.TARGET_DATE = CAST(#{workDate} AS DATE)
  AND r.STATUS IN ('DRAFT', 'SUBMITTED', 'APPROVED')

      AND r.REQ_ID <> #{requestId}



          AND r.REQ_GROUP = 'OTHER'
          AND o.CHANGE_SHIFT_CODE = #{requestWorkCode}


          AND r.REQ_GROUP = 'GENERAL'
          AND r.REQ_TYPE = #{requestWorkCode}

mapper.update:
UPDATE HRTATTENDANCE_OTHER01
SET CHANGE_SHIFT_CODE = #{requestWorkCode},
    UPDATED_AT        = GETDATE()
WHERE REQ_ID  = #{requestId}
  AND COMPANY = #{company}

mapper.select:
SELECT DEPT_LEADER
FROM ORGDEPTMASTER01
WHERE COMPANY = #{company}
  AND DEPT_CODE = #{deptCode}

SELECT COUNT(*)
FROM HRTATTENDANCEREQUEST01
WHERE COMPANY         = #{company}
  AND TARGET_EMP_CODE = #{empCode}
  AND TARGET_DATE     = CAST(#{workDate} AS DATE)
  AND STATUS IN ('DRAFT', 'SUBMITTED', 'APPROVED')
  AND REQ_GROUP = 'GENERAL'

      AND REQ_ID <> #{requestId}



          AND REQ_TYPE = '조퇴'


          AND REQ_TYPE IN ('연장', '조출연장')
